function debounce(fn, delay, options = {}) {
  const { leading = false, trailing = true } = options
  let timer = null
  let lastArgs = null
  let leadingCalled = false

  const debounced = function (...args) {
    lastArgs = args

    if (timer) {
      clearTimeout(timer)
    }

    if (leading && !leadingCalled) {
      leadingCalled = true
      fn.apply(this, args)
    }

    timer = setTimeout(() => {
      if (trailing && lastArgs) {
        fn.apply(this, lastArgs)
      }
      timer = null
      leadingCalled = false
      lastArgs = null
    }, delay)
  }

  debounced.cancel = function () {
    if (timer) {
      clearTimeout(timer)
    }
    timer = null
    leadingCalled = false
    lastArgs = null
  }

  return debounced
}
```

**用法：**

```javascript
const handleSearch = debounce(
  (query) => fetch(`/api/search?q=${query}`),
  300
)

input.addEventListener('input', (e) => handleSearch(e.target.value))
```

**关键点：**

- **leading / trailing** — leading 在首次调用时立即执行，trailing 在停止触发 delay 毫秒后执行。默认 trailing 为 true，与 Lodash 行为一致。
- **this 绑定** — 通过 `fn.apply(this, args)` 保留调用时的上下文。
- **cancel 方法** — 可手动清除未执行的调用（如组件卸载时）。

如果你只想要最简版本：

```javascript
function debounce(fn, delay) {
  let timer
  return function (...args) {
    clearTimeout(timer)
    timer = setTimeout(() => fn.apply(this, args), delay)
  }
}
```

